// Extrae los datos del body enviado por Laravel
const body = $json.body ?? $json;

// Mapeamos los campos según la nueva estructura
const titular = body.titular;
const copropietarios = body.copropietarios ?? [];
const evento = body.evento ?? '';
const plantilla = body.plantilla ?? {};

// Usamos el título de la plantilla como asunto predeterminado
const asunto = plantilla.titulo ?? 'Invitación al evento';

let finalItems = [];

// 1. Añadimos al Titular (Propietario) si existe y tiene envíos pendientes
if (titular) {
    if (titular.enviar_email || titular.enviar_whatsapp) {
        finalItems.push({
            json: {
                id: titular.id,
                email: titular.email,
                nombres: titular.nombres,
                celular: titular.celular ?? '',
                dni: titular.dni ?? '',
                link: titular.link,
                html: titular.html,
                tipo: 'Propietario',
                asunto: asunto,
                evento: evento,
                // --- BANDERAS DE ENVÍO ---
                enviar_email: titular.enviar_email,
                enviar_whatsapp: titular.enviar_whatsapp,
                // --- CAMPOS DE LA PLANTILLA ---
                plantilla_titulo: plantilla.titulo ?? '',
                plantilla_subtitulo: plantilla.subtitulo ?? '',
                plantilla_descripcion: plantilla.descripcion ?? '',
                plantilla_imagen: plantilla.imagen_url ?? '',
                plantilla_link_boton: plantilla.link_boton ?? ''
            }
        });
    }
}

// 2. Recorremos y añadimos a cada Copropietario si tiene envíos pendientes
copropietarios.forEach(cp => {
    if (cp.enviar_email || cp.enviar_whatsapp) {
        finalItems.push({
            json: {
                id: cp.id,
                email: cp.email ?? '',
                nombres: cp.nombres,
                celular: cp.celular ?? '',
                dni: cp.dni ?? '',
                link: cp.link,
                html: cp.html,
                tipo: 'Copropietario',
                asunto: asunto,
                evento: evento,
                // --- BANDERAS DE ENVÍO ---
                enviar_email: cp.enviar_email,
                enviar_whatsapp: cp.enviar_whatsapp,
                // --- CAMPOS DE LA PLANTILLA ---
                plantilla_titulo: plantilla.titulo ?? '',
                plantilla_subtitulo: plantilla.subtitulo ?? '',
                plantilla_descripcion: plantilla.descripcion ?? '',
                plantilla_imagen: plantilla.imagen_url ?? '',
                plantilla_link_boton: plantilla.link_boton ?? ''
            }
        });
    }
});

return finalItems;
